import{_ as l,c as n,o as a,a1 as i,j as e,a as s,t as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse(`{"title":"OpenCode Agent Skills: Introduction | opencode-agent-skills","description":"Discover OpenCode Agent Skills plugin's core value: dynamic skill discovery, context injection, compression recovery, intelligent recommendations, Claude Code compatibility, and Superpowers integration. Efficiently manage and reuse AI skills with cross-session persistence and automated recommendations.","frontmatter":{"title":"OpenCode Agent Skills: Introduction | opencode-agent-skills","subtitle":"What is OpenCode Agent Skills?","sidebarTitle":"Introduction","description":"Discover OpenCode Agent Skills plugin's core value: dynamic skill discovery, context injection, compression recovery, intelligent recommendations, Claude Code compatibility, and Superpowers integration. Efficiently manage and reuse AI skills with cross-session persistence and automated recommendations.","tags":["Getting Started","Plugin Introduction"],"prerequisite":[],"order":1},"headers":[],"relativePath":"joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md","filePath":"joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"}`),d={name:"joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"},c={tabindex:"0"};function u(o,t,p,h,m,g){return a(),n("div",null,[t[8]||(t[8]=i(`<h1 id="what-is-opencode-agent-skills" tabindex="-1">What is OpenCode Agent Skills? <a class="header-anchor" href="#what-is-opencode-agent-skills" aria-label="Permalink to &quot;What is OpenCode Agent Skills?&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understand the core value of the OpenCode Agent Skills plugin</li><li>Master the main features provided by the plugin</li><li>Understand how skills are automatically discovered and loaded</li><li>Distinguish this plugin from other skill management solutions</li></ul><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><p>You may have encountered these situations:</p><ul><li><strong>Difficulty managing scattered skills</strong>: Skills are scattered across multiple locations like project directories, user directories, and plugin caches, making it hard to find the right skill</li><li><strong>Long sessions become troublesome</strong>: After long sessions, previously loaded skills become invalid due to context compression</li><li><strong>Compatibility anxiety</strong>: Concerned that existing skills and plugins won&#39;t work after migrating from Claude Code</li><li><strong>Repetitive configuration</strong>: Need to reconfigure skills for each project, lacking a unified skill management mechanism</li></ul><p>These issues are all affecting your efficiency when using AI assistants.</p><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p><strong>OpenCode Agent Skills</strong> is a plugin system that provides dynamic skill discovery and management capabilities for OpenCode.</p><div class="info custom-block"><p class="custom-block-title">What is a skill?</p><p>A skill is a reusable module containing AI workflow guidance. It is typically a directory that includes a <code>SKILL.md</code> file (describing the skill&#39;s functionality and usage), along with possible supporting files (documentation, scripts, etc.).</p></div><p><strong>Core Value</strong>: By standardizing skill formats (SKILL.md), it achieves skill reuse across projects and sessions.</p><h3 id="technical-architecture" tabindex="-1">Technical Architecture <a class="header-anchor" href="#technical-architecture" aria-label="Permalink to &quot;Technical Architecture&quot;">​</a></h3><p>The plugin is built with TypeScript + Bun + Zod, providing 4 core tools:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Function</th></tr></thead><tbody><tr><td><code>use_skill</code></td><td>Injects the SKILL.md content of a skill into the session context</td></tr><tr><td><code>read_skill_file</code></td><td>Reads supporting files (documentation, configs, etc.) from the skill directory</td></tr><tr><td><code>run_skill_script</code></td><td>Executes executable scripts in the skill directory context</td></tr><tr><td><code>get_available_skills</code></td><td>Retrieves the list of currently available skills</td></tr></tbody></table><h2 id="main-features" tabindex="-1">Main Features <a class="header-anchor" href="#main-features" aria-label="Permalink to &quot;Main Features&quot;">​</a></h2><h3 id="_1-dynamic-skill-discovery" tabindex="-1">1. Dynamic Skill Discovery <a class="header-anchor" href="#_1-dynamic-skill-discovery" aria-label="Permalink to &quot;1. Dynamic Skill Discovery&quot;">​</a></h3><p>The plugin automatically discovers skills from multiple locations, sorted by priority:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. .opencode/skills/              (Project-level - OpenCode)</span></span>
<span class="line"><span>2. .claude/skills/                (Project-level - Claude Code)</span></span>
<span class="line"><span>3. ~/.config/opencode/skills/     (User-level - OpenCode)</span></span>
<span class="line"><span>4. ~/.claude/skills/              (User-level - Claude Code)</span></span>
<span class="line"><span>5. ~/.claude/plugins/cache/        (Plugin cache)</span></span>
<span class="line"><span>6. ~/.claude/plugins/marketplaces/ (Installed plugins)</span></span></code></pre></div><p><strong>Rule</strong>: The first matching skill takes effect; subsequent skills with the same name are ignored.</p><blockquote><p>Why this design?</p><p>Project-level skills take priority over user-level skills, so you can customize specific behaviors in projects without affecting global configuration.</p></blockquote><h3 id="_2-context-injection" tabindex="-1">2. Context Injection <a class="header-anchor" href="#_2-context-injection" aria-label="Permalink to &quot;2. Context Injection&quot;">​</a></h3><p>When you call <code>use_skill</code>, the skill content is injected into the session context in XML format:</p><ul><li><code>noReply: true</code> - The AI will not respond to the injected message</li><li><code>synthetic: true</code> - Marked as a system-generated message (not displayed in UI, not counted as user input)</li></ul><p>This means skill content persists in the session context, remaining available even as the session grows and context compression occurs.</p><h3 id="_3-compression-recovery-mechanism" tabindex="-1">3. Compression Recovery Mechanism <a class="header-anchor" href="#_3-compression-recovery-mechanism" aria-label="Permalink to &quot;3. Compression Recovery Mechanism&quot;">​</a></h3><p>When OpenCode performs context compression (common in long sessions), the plugin listens for the <code>session.compacted</code> event and automatically re-injects the list of available skills.</p><p>This ensures that the AI always knows which skills are available in long sessions, preventing loss of skill access due to compression.</p><h3 id="_4-claude-code-compatibility" tabindex="-1">4. Claude Code Compatibility <a class="header-anchor" href="#_4-claude-code-compatibility" aria-label="Permalink to &quot;4. Claude Code Compatibility&quot;">​</a></h3><p>The plugin is fully compatible with Claude Code&#39;s skill and plugin system, supporting:</p><ul><li>Claude Code skills (<code>.claude/skills/&lt;skill-name&gt;/SKILL.md</code>)</li><li>Claude plugin cache (<code>~/.claude/plugins/cache/...</code>)</li><li>Claude plugin marketplace (<code>~/.claude/plugins/marketplaces/...</code>)</li></ul><p>This means if you previously used Claude Code, you can continue using your existing skills and plugins after migrating to OpenCode.</p><h3 id="_5-automatic-skill-recommendations" tabindex="-1">5. Automatic Skill Recommendations <a class="header-anchor" href="#_5-automatic-skill-recommendations" aria-label="Permalink to &quot;5. Automatic Skill Recommendations&quot;">​</a></h3><p>The plugin monitors your messages and uses semantic similarity to detect whether they relate to any available skill:</p><ul><li>Computes the embedding vector of your message</li><li>Calculates cosine similarity with all skill descriptions</li><li>When similarity exceeds a threshold, injects an evaluation prompt suggesting the AI load relevant skills</li></ul><p>This process is completely automatic—you don&#39;t need to remember skill names or explicitly request them.</p><h3 id="_6-superpowers-integration-optional" tabindex="-1">6. Superpowers Integration (Optional) <a class="header-anchor" href="#_6-superpowers-integration-optional" aria-label="Permalink to &quot;6. Superpowers Integration (Optional)&quot;">​</a></h3><p>The plugin supports the Superpowers workflow, enabled via environment variable:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opencode</span></span></code></pre></div><p>When enabled, the plugin automatically detects the <code>using-superpowers</code> skill and injects complete workflow guidance during session initialization.</p><h2 id="comparison-with-other-solutions" tabindex="-1">Comparison with Other Solutions <a class="header-anchor" href="#comparison-with-other-solutions" aria-label="Permalink to &quot;Comparison with Other Solutions&quot;">​</a></h2>`,40)),e("table",c,[t[7]||(t[7]=e("thead",null,[e("tr",null,[e("th",null,"Solution"),e("th",null,"Features"),e("th",null,"Use Cases")])],-1)),e("tbody",null,[t[4]||(t[4]=e("tr",null,[e("td",null,[e("strong",null,"opencode-agent-skills")]),e("td",null,"Dynamic discovery, compression recovery, auto recommendations"),e("td",null,"Scenarios requiring unified management and automated recommendations")],-1)),e("tr",null,[t[2]||(t[2]=e("td",null,[e("strong",null,"opencode-skills")],-1)),e("td",null,[t[0]||(t[0]=s("Auto-registers as ",-1)),e("code",null,"skills_"+r(o.name),1),t[1]||(t[1]=s(" tools",-1))]),t[3]||(t[3]=e("td",null,"Scenarios requiring independent tool calls",-1))]),t[5]||(t[5]=e("tr",null,[e("td",null,[e("strong",null,"superpowers")]),e("td",null,"Complete software development workflow"),e("td",null,"Projects requiring strict process standards")],-1)),t[6]||(t[6]=e("tr",null,[e("td",null,[e("strong",null,"skillz")]),e("td",null,"MCP server mode"),e("td",null,"Scenarios requiring skills across different tools")],-1))])]),t[9]||(t[9]=i('<p>Reasons to choose this plugin:</p><ul><li>✅ <strong>Zero configuration</strong>: Automatically discovers and manages skills</li><li>✅ <strong>Smart recommendations</strong>: Automatically recommends relevant skills based on semantic matching</li><li>✅ <strong>Compression recovery</strong>: Stable and reliable in long sessions</li><li>✅ <strong>Compatibility</strong>: Seamless migration of Claude Code skills</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The OpenCode Agent Skills plugin provides complete skill management capabilities for OpenCode through core mechanisms like dynamic discovery, context injection, and compression recovery. Its core value lies in:</p><ul><li><strong>Automation</strong>: Reduces the burden of manual configuration and remembering skill names</li><li><strong>Stability</strong>: Skills remain available throughout long sessions</li><li><strong>Compatibility</strong>: Seamless integration with the existing Claude Code ecosystem</li></ul><h2 id="preview-next-lesson" tabindex="-1">Preview: Next Lesson <a class="header-anchor" href="#preview-next-lesson" aria-label="Permalink to &quot;Preview: Next Lesson&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../installation/">Installing OpenCode Agent Skills</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to add the plugin to OpenCode configuration</li><li>How to verify the plugin is correctly installed</li><li>Local development mode setup methods</li></ul></blockquote><hr><h2 id="appendix-source-code-references" tabindex="-1">Appendix: Source Code References <a class="header-anchor" href="#appendix-source-code-references" aria-label="Permalink to &quot;Appendix: Source Code References&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>Plugin entry and functionality overview</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L1-L12" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>1-12</td></tr><tr><td>Core feature list</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/README.md#L5-L11" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>5-11</td></tr><tr><td>Skill discovery priority</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L246" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-246</td></tr><tr><td>Synthetic message injection</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Compression recovery mechanism</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L151" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-151</td></tr><tr><td>Semantic matching module</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/embeddings.ts#L108-L135" target="_blank" rel="noreferrer"><code>src/embeddings.ts</code></a></td><td>108-135</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>EMBEDDING_MODEL = &quot;Xenova/all-MiniLM-L6-v2&quot;</code>: The embedding model used</li><li><code>SIMILARITY_THRESHOLD = 0.35</code>: Semantic similarity threshold</li><li><code>TOP_K = 5</code>: Maximum number of skills returned for auto-recommendation</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>discoverAllSkills()</code>: Discovers skills from multiple locations</li><li><code>use_skill()</code>: Injects skill content into session context</li><li><code>matchSkills()</code>: Matches relevant skills based on semantic similarity</li><li><code>injectSyntheticContent()</code>: Injects synthetic messages into session</li></ul></details>',10))])}const y=l(d,[["render",u]]);export{b as __pageData,y as default};
